import{_ as r,o as a,c as e,a2 as d}from"./chunks/framework.BEgbRHOA.js";const c=JSON.parse('{"title":"Обзор системы xkurier","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1775748865000}'),i={name:"guide/index.md"};function o(n,t,l,s,h,u){return a(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="обзор-системы-xkurier" tabindex="-1">Обзор системы xkurier <a class="header-anchor" href="#обзор-системы-xkurier" aria-label="Permalink to &quot;Обзор системы xkurier&quot;">​</a></h1><p><strong>xkurier</strong> — полноценная система доставки продуктов, состоящая из трёх приложений и серверной части.</p><h2 id="компоненты-системы" tabindex="-1">Компоненты системы <a class="header-anchor" href="#компоненты-системы" aria-label="Permalink to &quot;Компоненты системы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Приложение</th><th>Для кого</th><th>Платформы</th></tr></thead><tbody><tr><td><strong>xcourier</strong></td><td>Клиенты (покупатели)</td><td>iOS, Android</td></tr><tr><td><strong>xcourier_manager</strong></td><td>Менеджеры магазинов</td><td>iOS, Android</td></tr><tr><td><strong>xcourier_admin</strong></td><td>Администраторы платформы</td><td>iOS, Android</td></tr></tbody></table><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><ol><li><strong>Клиент</strong> открывает приложение xcourier, выбирает магазин, добавляет товары в корзину и оформляет заказ.</li><li><strong>Менеджер магазина</strong> получает уведомление о новом заказе в xcourier_manager, собирает заказ и меняет его статус.</li><li><strong>Администратор</strong> через xcourier_admin управляет магазинами, менеджерами, баннерами и видит аналитику по заказам.</li></ol><h2 id="серверная-часть" tabindex="-1">Серверная часть <a class="header-anchor" href="#серверная-часть" aria-label="Permalink to &quot;Серверная часть&quot;">​</a></h2><ul><li><strong>Firebase Firestore</strong> — основная база данных (real-time синхронизация)</li><li><strong>Firebase Auth</strong> — аутентификация пользователей</li><li><strong>Firebase Cloud Functions</strong> — бизнес-логика (создание заказов, расчёт доставки, push-уведомления)</li><li><strong>Yandex Cloud Object Storage</strong> — хранение изображений товаров</li></ul><h2 id="статусы-заказа" tabindex="-1">Статусы заказа <a class="header-anchor" href="#статусы-заказа" aria-label="Permalink to &quot;Статусы заказа&quot;">​</a></h2><p>Каждый заказ проходит через цепочку статусов:</p><table tabindex="0"><thead><tr><th>Статус</th><th>Описание</th></tr></thead><tbody><tr><td>Создан</td><td>Заказ только что оформлен клиентом</td></tr><tr><td>Собирается</td><td>Менеджер начал сборку заказа</td></tr><tr><td>Собран</td><td>Заказ собран, ожидает курьера</td></tr><tr><td>В пути</td><td>Курьер забрал заказ и едет к клиенту</td></tr><tr><td>Завершен</td><td>Заказ успешно доставлен</td></tr><tr><td>Отменен</td><td>Заказ отменён</td></tr></tbody></table><h2 id="способы-оплаты" tabindex="-1">Способы оплаты <a class="header-anchor" href="#способы-оплаты" aria-label="Permalink to &quot;Способы оплаты&quot;">​</a></h2><p>Система поддерживает два способа оплаты:</p><ul><li><strong>Наличные</strong> — оплата курьеру при получении</li><li><strong>СБП</strong> — оплата с карты через Систему быстрых платежей (в разработке)</li></ul><h2 id="способы-доставки" tabindex="-1">Способы доставки <a class="header-anchor" href="#способы-доставки" aria-label="Permalink to &quot;Способы доставки&quot;">​</a></h2><ul><li><strong>Курьерская доставка</strong> — доставка по указанному адресу</li><li><strong>Самовывоз</strong> — самостоятельный забор из магазина</li></ul>',16)])])}const x=r(i,[["render",o]]);export{c as __pageData,x as default};
